+import Yoga, {type Node as YogaNode} from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track = {min: number; fr: number; auto: boolean};
+type Placement = {start?: number; end?: number};
+
+const parseTracks = (template: string | undefined): Track[] => {
+	if (!template) return [];
+	const tokens = template.match(/minmax\\([^)]*\\)|\\S+/g) ?? [];
+	return tokens.map(token => {
+		if (token === 'auto') return {min: 0, fr: 0, auto: true};
+		const minmax = /^minmax\\(\\s*(\\d+(?:\\.\\d+)?)\\s*,\\s*(\\d+(?:\\.\\d+)?(?:fr)?)\\s*\\)$/.exec(token);
+		if (minmax) {
+			return {
+				min: Number(minmax[1]),
+				fr: minmax[2]!.endsWith('fr') ? Number.parseFloat(minmax[2]!) : 0,
+				auto: false,
+			};
+		}
+		if (token.endsWith('fr')) return {min: 0, fr: Number.parseFloat(token), auto: false};
+		const size = Number(token);
+		return {min: Number.isFinite(size) ? size : 0, fr: 0, auto: false};
+	});
+};
+
+const parsePlacement = (value: number | string | undefined): Placement => {
+	if (typeof value === 'number') return {start: value};
+	if (!value) return {};
+	const match = /^(\\d+)\\s*\\/\\s*(\\d+)$/.exec(value.trim());
+	return match ? {start: Number(match[1]), end: Number(match[2])} : {};
+};
+
+const gap = (node: YogaNode, gutter: number): number => node.getGap(gutter);
+
+const resetGridChildren = (node: DOMElement): void => {
+	for (const child of node.childNodes) {
+		const element = child as DOMElement;
+		if (node.style.display === 'grid' && element.yogaNode) {
+			const yoga = element.yogaNode;
+			yoga.setPositionType(Yoga.POSITION_TYPE_RELATIVE);
+			yoga.setPosition(Yoga.EDGE_LEFT, undefined);
+			yoga.setPosition(Yoga.EDGE_TOP, undefined);
+			if (element.style.width === undefined) yoga.setWidthAuto();
+			if (element.style.height === undefined) yoga.setHeightAuto();
+		}
+		if (element.nodeName !== '#text') resetGridChildren(element);
+	}
+	if (node.style.display === 'grid' && node.style.height === undefined) {
+		node.yogaNode?.setHeightAuto();
+	}
+};
+
+const resolveTracks = (tracks: Track[], available: number, gapSize: number, autoSizes: number[]): number[] => {
+	const sizes = tracks.map((track, index) => track.auto ? Math.max(track.min, autoSizes[index] ?? 0) : track.min);
+	const remaining = Math.max(0, available - sizes.reduce((sum, size) => sum + size, 0) - Math.max(0, tracks.length - 1) * gapSize);
+	const totalFr = tracks.reduce((sum, track) => sum + track.fr, 0);
+	if (totalFr > 0) tracks.forEach((track, index) => { sizes[index]! += remaining * track.fr / totalFr; });
+	return sizes;
+};
+
+const spanSize = (sizes: number[], start: number, end: number, gapSize: number): number =>
+	sizes.slice(start, end).reduce((sum, size) => sum + size, 0) + Math.max(0, end - start - 1) * gapSize;
+
+const layoutGrid = (node: DOMElement): void => {
+	const yoga = node.yogaNode!;
+	const children = node.childNodes.filter((child): child is DOMElement => Boolean((child as DOMElement).yogaNode));
+	let columns = parseTracks(node.style.gridTemplateColumns);
+	if (columns.length === 0) columns = [{min: 0, fr: 1, auto: false}];
+	const placements = children.map(child => ({child, column: parsePlacement(child.style.gridColumn), row: parsePlacement(child.style.gridRow)}));
+	let nextColumn = 1;
+	let nextRow = 1;
+	for (const placement of placements) {
+		if (placement.column.start && placement.row.start) continue;
+		if (!placement.column.start) placement.column.start = nextColumn;
+		if (!placement.row.start) placement.row.start = nextRow;
+		placement.column.end ??= placement.column.start + 1;
+		placement.row.end ??= placement.row.start + 1;
+		nextColumn = placement.column.end;
+		if (nextColumn > columns.length) { nextColumn = 1; nextRow++; }
+	}
+	for (const placement of placements) {
+		placement.column.end ??= placement.column.start! + 1;
+		placement.row.end ??= placement.row.start! + 1;
+	}
+	const rowCount = Math.max(1, ...placements.map(placement => placement.row.end! - 1));
+	let rows = parseTracks(node.style.gridTemplateRows);
+	while (rows.length < rowCount) rows.push({min: 0, fr: 0, auto: true});
+	const columnGap = gap(yoga, Yoga.GUTTER_COLUMN);
+	const rowGap = gap(yoga, Yoga.GUTTER_ROW);
+	const contentWidth = yoga.getComputedWidth() - yoga.getComputedPadding(Yoga.EDGE_LEFT) - yoga.getComputedPadding(Yoga.EDGE_RIGHT) - yoga.getComputedBorder(Yoga.EDGE_LEFT) - yoga.getComputedBorder(Yoga.EDGE_RIGHT);
+	const columnAutos = columns.map((_, index) => Math.max(0, ...placements.filter(p => p.column.start === index + 1 && p.column.end === index + 2).map(p => p.child.yogaNode!.getComputedWidth())));
+	const columnSizes = resolveTracks(columns, contentWidth, columnGap, columnAutos);
+	const rowAutos = rows.map((_, index) => Math.max(0, ...placements.filter(p => p.row.start === index + 1 && p.row.end === index + 2).map(p => p.child.yogaNode!.getComputedHeight())));
+	const contentHeight = yoga.getComputedHeight() - yoga.getComputedPadding(Yoga.EDGE_TOP) - yoga.getComputedPadding(Yoga.EDGE_BOTTOM) - yoga.getComputedBorder(Yoga.EDGE_TOP) - yoga.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const rowSizes = resolveTracks(rows, contentHeight, rowGap, rowAutos);
+	if (node.style.height === undefined) yoga.setHeight(rowSizes.reduce((sum, size) => sum + size, 0) + Math.max(0, rows.length - 1) * rowGap + yoga.getComputedPadding(Yoga.EDGE_TOP) + yoga.getComputedPadding(Yoga.EDGE_BOTTOM) + yoga.getComputedBorder(Yoga.EDGE_TOP) + yoga.getComputedBorder(Yoga.EDGE_BOTTOM));
+	for (const placement of placements) {
+		const child = placement.child.yogaNode!;
+		const columnStart = placement.column.start! - 1;
+		const rowStart = placement.row.start! - 1;
+		const columnEnd = Math.min(columns.length, placement.column.end! - 1);
+		const rowEnd = Math.min(rows.length, placement.row.end! - 1);
+		child.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		child.setPosition(Yoga.EDGE_LEFT, columnSizes.slice(0, columnStart).reduce((sum, size) => sum + size, 0) + columnStart * columnGap);
+		child.setPosition(Yoga.EDGE_TOP, rowSizes.slice(0, rowStart).reduce((sum, size) => sum + size, 0) + rowStart * rowGap);
+		child.setWidth(spanSize(columnSizes, columnStart, columnEnd, columnGap));
+		child.setHeight(spanSize(rowSizes, rowStart, rowEnd, rowGap));
+	}
+};
+
+const applyGridLayout = (node: DOMElement): void => {
+	if (node.style.display === 'grid' && node.yogaNode) layoutGrid(node);
+	for (const child of node.childNodes) if ((child as DOMElement).nodeName !== '#text') applyGridLayout(child as DOMElement);
+};
+
+export const calculateLayout = (root: DOMElement, width?: number): void => {
+	resetGridChildren(root);
+	if (width !== undefined) root.yogaNode!.setWidth(width);
+	root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	applyGridLayout(root);
+	root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+};
